$repos = 'designflow-backend','designflow-bff','designflow-data-syncing','designflow-frontend','designflow-item-master','designflow-tracking'
foreach ($r in $repos) {
  $out = gh api "repos/popcre/$r/merges" -f base=sandbox-albert -f head=develop -f commit_message="Merge develop into sandbox-albert" 2>&1
  $code = $LASTEXITCODE
  if ($code -eq 0) {
    if ([string]::IsNullOrWhiteSpace($out)) {
      "{0}: ALREADY UP TO DATE (nothing to merge)" -f $r
    } else {
      $sha = ($out | ConvertFrom-Json).sha
      "{0}: MERGED  commit={1}" -f $r, $sha.Substring(0,8)
    }
  } else {
    "{0}: ERROR -> {1}" -f $r, ($out -join ' ')
  }
}

$repos = 'designflow-backend','designflow-bff','designflow-data-syncing','designflow-frontend','designflow-item-master','designflow-tracking'
foreach ($r in $repos) {
  $p = "C:\repos\dflow\$r"
  $out = git -C $p pull --ff origin sandbox-albert 2>&1
  $code = $LASTEXITCODE
  $status = if ($code -eq 0) { "OK" } else { "FAILED($code)" }
  "=== {0}: {1} ===" -f $r, $status
  $out | Select-Object -Last 6
  ""
}

$repos = 'designflow-backend','designflow-bff','designflow-data-syncing','designflow-frontend','designflow-item-master','designflow-tracking'
foreach ($r in $repos) {
  $p = "C:\repos\dflow\$r"
  $st = git -C $p status --porcelain 2>$null
  "=== {0} ===" -f $r
  if ([string]::IsNullOrWhiteSpace($st)) { "  (clean)" } else { $st | ForEach-Object { "  $_" } }
}

